1	type ScenarioResult = { premium?: number; payout?: number };
2	type ScenarioOutput = { results: ScenarioResult[] };
3	
4	type Item = { type: string };
5	type Step = { op: string; items: Item[] };
6	type Input = { steps: Step[] };
7	
8	const PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
9	  sword: 115,
10	  amulet: 71,
11	};
12	
13	export function runScenario(input: unknown): ScenarioOutput {
14	  const { steps } = input as Input;
15	  const itemType = steps[0].items[0].type;
16	  const premium = PREMIUM_BY_ITEM_TYPE[itemType];
17	  return { results: [{ premium }] };
18	}
